+void shell_printprefix(const char* user, const char* pcname, const char* directory) {
+    char home[256];
+    int pos = 0;
+
+    if (streql(user, "root")) {
+        const char* base = "/root";
+        for (int i = 0; base[i] && pos < 255; i++)
+            home[pos++] = base[i];
+        home[pos] = 0;
+    } else {
+        const char* base = "/home/";
+        for (int i = 0; base[i] && pos < 255; i++)
+            home[pos++] = base[i];
+        for (int i = 0; user[i] && pos < 255; i++)
+            home[pos++] = user[i];
+        home[pos] = 0;
+    }
+
+    const char* shown = directory;
+    int match = 1;
+
+    for (int i = 0; home[i]; i++) {
+        if (directory[i] != home[i]) {
+            match = 0;
+            break;
+        }
+    }
+
+    if (match) {
+        shown = "~";
+    }
+
+    print(user, 0x0B);
+    print("@", 0x07);
+    print(pcname, 0x0B);
+    print(":", 0x07);
+    print(shown, 0x0B);
+    print(" $ ", 0x0F);
+}
